const Nav = () => {
    return (
        <nav className="nav">
            <ul>
                <li><a href="#home">Home</a></li>
                <li><a href="#about">About</a></li>
                <li><a href="#reservation">Reservation</a></li>
                <li><a href="#login">Login</a></li>
            </ul>
        </nav>
    );
}

export default Nav;
